var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"침식체가 계속 몰려와! 정말 이대로 괜찮은 거 맞아?","JPN":"侵食体がとめどなく押し寄せてくるわ！　本当にこのままで大丈夫なの？","ENG":"C.O.s won't stop coming! Can we really survive this?","TWN":"侵蝕體正不斷地湧來！這樣下去真的沒問題嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"한눈 팔지 말고 집중하세요!","JPN":"わき目をふらずに集中を！　","ENG":"Stop talking and focus!","TWN":"不要東張西望，集中注意力！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전선을 사수하고 있으면 사령관님께서 해결책을 마련하실 겁니다!","JPN":"我々が戦線を死守する間、司令官が対策を講じるはずです！","ENG":"If we just keep fighting, the Commander will come up with a solution.","TWN":"只要死守住前線，司令官大人一定有辦法解決的！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......상황이 좋지 않군.","JPN":"……まずい状況になったな。","ENG":"The situation is not in our favor.","TWN":"……情況不太好呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크!","JPN":"ジェイク！","ENG":"Jake!","TWN":"傑克！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네? 네! 사령관님!","JPN":"はい？　はい！　司令官！","ENG":"Huh? Yes, Commander!","TWN":"什麼？是的！司令官！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금부터 이곳의 지휘는 자네에게 맡긴다.","JPN":"これよりここの指揮は君に任せる。","ENG":"I'm leaving you in charge of this place.","TWN":"現在開始，這裡就交給你指揮了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아와 카일을 이끌고 등대를 방어하도록.","JPN":"シルビアやカイルとともに灯台を守るように。","ENG":"Protect the Lighthouse with Sylvia and Kyle.","TWN":"你帶著希爾維亞和凱爾，去燈塔那裡進行防衛。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네? 그럼 사령관님은......?","JPN":"はい？　では、司令官は……？","ENG":"Huh? But what about you, Commander?","TWN":"咦？那司令官呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나는 뉴 오하이오로 차원 폭풍 내부에 돌입하여 도미닉과 선발대를 구원하러 가겠다.","JPN":"私はニューオハイオで次元の暴風の中に入り、ドミニークと選抜隊を助けにいく。","ENG":"I'm going to drive the New Ohio into the dimensional storm and save Dominic and his advance party.","TWN":"我要坐新俄亥俄衝進次元風暴內部，去救出多明尼克和先頭部隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님 혼자서 말입니까? 하지만 그건 너무 위험합니다.","JPN":"司令官一人でですか？　それは危険過ぎます。","ENG":"By yourself, Commander? That's too dangerous.","TWN":"司令官一個人去？可是那樣太危險了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"걱정 말게. 위험한 작전이 바로 내 특기니까.","JPN":"案ずるな。危険な作戦こそが私の専門だからな。","ENG":"Don't worry. Dangerous operations are my forte.","TWN":"不用擔心，畢竟進行危險的作戰正是我的特長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 뉴 오하이오는 이런 불안정한 차원간 항해에 저항성을 가지도록 설계된 전략 함선이야.","JPN":"それに、ニューオハイオはこのように不安定な次元間の航海に耐えられるよう設計された戦略艦船だ。","ENG":"Besides, the New Ohio is a tactical ship designed to endure even the most unstable interdimensional trip.","TWN":"而且作為一艘戰略艦船，新俄亥俄正是被設計成能夠抵抗這種不穩定的次元間航行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"등대만 무사하다면 차원 폭풍 속이라고 해도 충분히 순항이 가능해.","JPN":"灯台さえ無事なら、次元の暴風の中でも十分巡航できる。","ENG":"So long as the Lighthouse is safe, she can sail smoothly, even inside the dimensional storm.","TWN":"只要燈塔沒事，就算在次元風暴內部也能夠順利航行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해도...... 제가 지휘를 맡을 수 있을지......","JPN":"ですが、そうは言っても……俺に指揮役がつとまるかどうか……","ENG":"But still... I don't know if I can command the others...","TWN":"就算如此……我有辦法擔負指揮的重任嗎……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍 속에서 연락이 두절되었다면 부사령관님이 무사할 가능성은 거의 없습니다.","JPN":"次元の暴風の中で音信不通になったなら、\\n副司令官が無事な可能性はほぼゼロです。","ENG":"The Deputy Commander is lost in the middle of that dimensional storm, and there's almost zero possibility of him returning safely.","TWN":"在次元風暴內部失去聯絡的話，副司令官幾乎不可能平安無事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차라리 살아남은 사람만이라도 모아 후퇴하시는 게......","JPN":"こうなった以上、生存メンバーだけでも集めて退却したほうが……","ENG":"Perhaps we should just leave with the others who are still here.","TWN":"我們還不如集合起倖存者撤退……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럴 수는 없지. 적어도 자네가 보고 있는 앞에서는 말이야.","JPN":"そういうわけにはいかない。少なくとも君が見てる前ではな。","ENG":"I can't do that. Not at least in front of you, that is.","TWN":"不能這麼做。至少不能在你面前這麼做。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네? 무슨 말씀이신지......","JPN":"はい？　おっしゃっている意味がよく……","ENG":"Pardon? I don't understand...","TWN":"咦？您是什麼意思……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 사상 최고의 CRF 출력을 기록한 애송이가 모든 제안을 거절하고 군에 지원했다는 이야기를 듣고는 뭐 그런 멍청이가 있나 했지.","JPN":"管理局史上最高のCRF出力を叩きだした若造があらゆる提案を断って\\n軍に志願したと聞いた時、とんでもないバカ野郎だと思ったのだ。","ENG":"When I heard the rookie who recorded the highest CRF output in the Administration's history had declined all the amazing offers he had and applied for the Army, I thought he was stupid.","TWN":"聽說有個小鬼創下管理局史上最佳CRF輸出記錄，卻拒絕了所有提案，志願來到軍隊，我還在想怎麼會有這種傻子。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 멍청이가 하필이면 내 직속부대에 지원했다는 말을 듣고 누군지 구경이나 해볼까 했었는데......","JPN":"そいつが私の直属部隊に志願したと言うものだから、\\nどんな奴か気になって見に行ったのだが……","ENG":"And when I heard he'd applied for my unit, I wanted to see his face.","TWN":"而且那個傻子偏偏志願到我的直屬部隊，我本想看看他究竟是誰……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"목숨을 바쳐 마을을 지킨 할아버지의 라이플을 들고 당돌하게 내 이름을 물어보던 꼬맹이가 제법 멋진 청년으로 바뀌어 있는 걸 보고 조금 놀랐었어.","JPN":"命がけで村を守ったおじいちゃんのライフルを持って\\n唐突に私の名前を聞いてきたチビッ子が、なかなか立派な青年に成長しているではないか。驚いたよ。","ENG":"It turned out he was the spunky kid who asked me for my name, holding a rifle in his hand, which his grandfather used to protect his village in exchange for his life.","TWN":"令我驚訝的是，當年那個拿著拚命保護村莊的爺爺的步槍，冒失地問了我名字的小鬼，現在已經變成了這麼英俊的青年。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 말씀은 설마...... 알고 계셨습니까?","JPN":"それは、まさか……気付いていたのですか？","ENG":"You mean... you knew?","TWN":"您這話，該不會是……知道我的事情吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"물론이지. 눈빛이 아주 인상 깊은 꼬마였거든.","JPN":"もちろんだ、まなざしがとても印象深いチビだったからな。","ENG":"Of course. The kid had a very impressive look in his eyes.","TWN":"那當然。畢竟那個小鬼的眼神非常令人印象深刻。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네는 사람들을 지키는 법을 배우기 위해 부귀영화도 마다하고 입대했다고 했지.","JPN":"君は人々を守る方法を学ぶために、出世の道も捨てて入隊したと言っていた。","ENG":"You turned down wealth and fame and joined the Army because you wanted to learn how to protect people.","TWN":"你說過你是為了學習保護人們的方法，所以才拒絕了榮華富貴加入部隊的對吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런 자네 앞에서 내가 전우들을 포기하는 모습을 보여줄 수 있겠나?","JPN":"そんな君の前で私が戦友を見捨てるところを見せられると思うか？","ENG":"How can I abandon my own people before someone like you?","TWN":"那我能在你的面前拋棄戰友嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 쪽팔려서라도 그런 짓은 못해.","JPN":"ハハ、そんな情けないことできるわけがない。","ENG":"Hah hah. I'm not that shameless.","TWN":"哈哈，就算會丟臉，我也做不到這種事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님......","JPN":"司令官……","ENG":"Commander.","TWN":"司令官……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네들에게 말은 하지 않았지만...... 이번 작전은 자네들의 졸업시험이다.","JPN":"これまで言わなかったが……今回の作戦は君たちの卒業試験だ。","ENG":"I didn't tell you, but this operation was your graduation test.","TWN":"雖然我沒有對你們說……但這次作戰是你們的畢業考試。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이번 작전이 끝나면 델타 세븐의 지휘관은 제이크 소령, 아니 중령 내정자인 자네가 맡게 될 예정이야.","JPN":"今回の作戦が終われば、デルタセブンの指揮はジェイク少佐、\\nいや、中佐内定者の君にまかせる予定だ。","ENG":"Once it's over, Delta Seven will be under the command of Major Jake, who will also be promoted lieutenant colonel.","TWN":"這次作戰結束後，第七三角洲的指揮官預定就會交給傑克少校，不，是中校來擔任。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제, 제가 말입니까?!","JPN":"お、俺がですか！？","ENG":"I-I am?","TWN":"我、我嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 델타 세븐 역시 내가 예편하는 대가로 더 이상 평가부대가 아닌 정식부대로 발령해 주기로 했네.","JPN":"そうだ。デルタセブンも私が引退する代わりに\\n評価部隊ではなく正規部隊の認定を受けることになっている。","ENG":"Yes. Delta Seven will also become an official unit, in return for my retirement.","TWN":"對。以我的退役為代價，第七三角洲部隊也不再是評估部隊，而是會以正式部隊的身份發受命令。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이제 늙다리들은 떠날 때가 된 거지.","JPN":"そろそろ老兵の去り際ということだ。","ENG":"It's time I make way for the younger generation.","TWN":"現在老傢伙該離開的時候到了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까?! 전 아직 배울 게 많이 남아 있습니다!","JPN":"何をおっしゃるんですか！？\\n俺にはまだご指導いただきたいことが山ほど……！　","ENG":"What are you talking about? I still have a lot to learn from you!","TWN":"您在說什麼啊？！我還有很多需要學習的東西！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네는 잘 해낼 거야. 내가 보증하지.","JPN":"君ならうまくやれるはずだ。私が保証しよう。","ENG":"You'll do just fine. Trust me.","TWN":"你會做得很好的，我保證。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 자신감을 가지게.","JPN":"だから、自信を持ちたまえ。","ENG":"Have confidence in yourself.","TWN":"所以請有點自信。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 안심하고 떠날 수 있도록 실력을 보여달라고.","JPN":"私が安心して旅立てるように、実力を見せてほしい。","ENG":"Show me that you can do this, so I can leave with a light heart.","TWN":"為了讓我能夠安心離開，你就展現你的實力給我看吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Yes, ma'am.","TWN":"……知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"맡겨만 주십시오.","JPN":"俺にお任せを。","ENG":"I won't disappoint you.","TWN":"請交給我吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 부탁하지!","JPN":"では、頼むぞ！","ENG":"Thank you.","TWN":"那就拜託你了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};